import React from "https://esm.sh/react@18.2.0";
import { createRoot } from "https://esm.sh/react-dom@18.2.0/client";

const canUseParentDoc = () => {
  try {
    return (
      window.parent &&
      window.parent !== window &&
      window.parent.document &&
      window.parent.document.body
    );
  } catch (_) {
    return false;
  }
};

const isNonEmptyString = (value) =>
  typeof value === "string" && value.trim().length > 0;

const MyCustomComponent = ({ data, updateData, runQuery }) => {
  const navItems = Array.isArray(data?.navItems) ? data.navItems : [];
  const theme =
    data?.theme === "dark" || data?.theme === "light" ? data.theme : "light";

  const [selectedSlugState, setSelectedSlugState] = React.useState(null);
  const selectedSlug = selectedSlugState;

  const [openMainKey, setOpenMainKey] = React.useState(null);

  const scrollerRef = React.useRef(null);

  const [canLeft, setCanLeft] = React.useState(false);
  const [canRight, setCanRight] = React.useState(false);

  const [openFor, setOpenFor] = React.useState(null);
  const [anchorEl, setAnchorEl] = React.useState(null);
  const [menuXY, setMenuXY] = React.useState({ top: 0, left: 0, minWidth: 200 });

  const portalElRef = React.useRef(null);
  const portalRootRef = React.useRef(null);
  const portalDocRef = React.useRef(null);

  const mainKeyOf = React.useCallback((item, idx) => {
    const s = item?.slug;
    if (s) return `m-${s}`;
    return `m-i${idx}-${String(item?.label ?? "")}`;
  }, []);

  const optKeyOf = React.useCallback((opt, idx) => {
    const s = opt?.slug;
    if (s) return `o-${s}`;
    return `o-i${idx}-${String(opt?.label ?? "")}`;
  }, []);

  /* ---------------- URL helpers ---------------- */

  const getCurrentHref = () => {
    try {
      if (canUseParentDoc()) return window.parent.location.href;
    } catch (_) {}
    return window.location.href;
  };

  const getCurrentSlugFromUrl = React.useCallback(() => {
    try {
      const href = getCurrentHref();
      const u = new URL(href);
      const p = u.pathname;

      let m = p.match(/\/apps\/([^\/]+)(?:\/.*)?$/);
      if (m && m[1]) return m[1];

      m = p.match(/\/applications\/([^\/]+)(?:\/.*)?$/);
      if (m && m[1]) return m[1];

      return null;
    } catch (_) {
      return null;
    }
  }, []);

  const navigateToSlug = React.useCallback(
    (slug) => {
      if (!isNonEmptyString(slug)) return false;

      const cleanSlug = slug.trim();
      const currentSlug = getCurrentSlugFromUrl();
      if (currentSlug && String(currentSlug) === String(cleanSlug)) return true;

      try {
        const href = getCurrentHref();
        const u = new URL(href);
        const p = u.pathname;

        let target = null;
        let m = p.match(/^(.*\/apps\/)([^\/]+)(?:\/.*)?$/);
        if (m) target = `${u.origin}${m[1]}${cleanSlug}`;
        else {
          m = p.match(/^(.*\/applications\/)([^\/]+)(?:\/.*)?$/);
          if (m) target = `${u.origin}${m[1]}${cleanSlug}`;
        }

        if (!target) return false;

        try {
          if (canUseParentDoc()) window.parent.location.assign(target);
          else window.location.assign(target);
        } catch (_) {
          window.location.assign(target);
        }
        return true;
      } catch (_) {
        return false;
      }
    },
    [getCurrentSlugFromUrl],
  );

  const navigateToUrl = React.useCallback((url, openInNewTab = false) => {
    if (!isNonEmptyString(url)) return false;

    const trimmedUrl = url.trim();
    const normalizedUrl = /^https?:\/\//i.test(trimmedUrl)
      ? trimmedUrl
      : `http://${trimmedUrl}`;

    try {
      if (openInNewTab) {
        window.open(normalizedUrl, "_blank", "noopener,noreferrer");
      } else if (canUseParentDoc()) {
        window.parent.location.assign(normalizedUrl);
      } else {
        window.location.assign(normalizedUrl);
      }
      return true;
    } catch (_) {
      try {
        if (openInNewTab) window.open(normalizedUrl, "_blank", "noopener,noreferrer");
        else window.location.assign(normalizedUrl);
        return true;
      } catch (__ ) {
        return false;
      }
    }
  }, []);

  const triggerMissingNavigationAlert = React.useCallback(() => {
    const message =
      data?.missingNavigationMessage ||
      "No app or URL is configured for this navigation item.";
    const queryName = data?.showAlertQueryName || "showAlertQuery";

    if (typeof runQuery === "function" && isNonEmptyString(queryName)) {
      try {
        runQuery(queryName, {
          type: "warning",
          message,
        });
        return;
      } catch (_) {}
    }

    try {
      window.alert(message);
    } catch (_) {}
  }, [data?.missingNavigationMessage, data?.showAlertQueryName, runQuery]);

  const handleNavigation = React.useCallback(
    (item, openInNewTab = false) => {
      const slug = isNonEmptyString(item?.slug) ? item.slug.trim() : "";
      const url = isNonEmptyString(item?.url) ? item.url.trim() : "";

      if (slug) {
        const didNavigate = navigateToSlug(slug);
        if (didNavigate) return;
      }

      if (url) {
        const didNavigate = navigateToUrl(url, openInNewTab);
        if (didNavigate) return;
      }

      triggerMissingNavigationAlert();
    },
    [navigateToSlug, navigateToUrl, triggerMissingNavigationAlert],
  );

  React.useEffect(() => {
    const currentSlug = getCurrentSlugFromUrl();
    if (!currentSlug) return;

    if (String(currentSlug) !== String(selectedSlugState)) {
      setSelectedSlugState(currentSlug);
      try {
        updateData({ ...data, selectedSlug: currentSlug });
      } catch (_) {}
    }
  }, [getCurrentSlugFromUrl, navItems]);

  /* ---------------- Scroll state ---------------- */

  const computeScrollState = React.useCallback(() => {
    const el = scrollerRef.current;
    if (!el) return;
    const tol = 2;
    const max = el.scrollWidth - el.clientWidth;
    setCanLeft(el.scrollLeft > tol);
    setCanRight(el.scrollLeft < max - tol);
  }, []);

  React.useEffect(() => {
    computeScrollState();
  }, [computeScrollState, navItems.length]);

  /* ---------------- Portal init ---------------- */

  React.useEffect(() => {
    const useParent = canUseParentDoc();
    const doc = useParent ? window.parent.document : document;
    portalDocRef.current = doc;

    const el = doc.createElement("div");
    el.style.position = "fixed";
    el.style.left = "0px";
    el.style.top = "0px";
    el.style.zIndex = "2147483647";
    doc.body.appendChild(el);

    portalElRef.current = el;
    portalRootRef.current = createRoot(el);

    return () => {
      try {
        portalRootRef.current?.unmount?.();
      } catch (_) {}
      try {
        doc.body.removeChild(el);
      } catch (_) {}
    };
  }, []);

  const getViewportOffsetIntoParent = () => {
    const useParent = portalDocRef.current && portalDocRef.current !== document;
    if (!useParent) return { dx: 0, dy: 0 };

    const fe = window.frameElement;
    if (!fe) return { dx: 0, dy: 0 };

    const r = fe.getBoundingClientRect();
    return { dx: r.left, dy: r.top };
  };

  const updateMenuPosition = React.useCallback((btnEl) => {
    if (!btnEl) return;

    const r = btnEl.getBoundingClientRect();
    const gap = 6;
    const { dx, dy } = getViewportOffsetIntoParent();

    const portalWin = portalDocRef.current?.defaultView || window;
    const vw = portalWin.innerWidth;
    const vh = portalWin.innerHeight;

    let top = dy + r.bottom + gap;
    let left = dx + r.left;
    const minWidth = Math.max(200, Math.floor(r.width));

    left = Math.max(6, Math.min(left, vw - minWidth - 6));
    setMenuXY({ top, left, minWidth });

    requestAnimationFrame(() => {
      const box = portalElRef.current?.querySelector?.("[data-menu-box='1']");
      if (!box) return;
      const mb = box.getBoundingClientRect();

      if (mb.bottom > vh - 6) {
        const flipped = dy + r.top - gap - mb.height;
        setMenuXY((p) => ({ ...p, top: Math.max(6, flipped) }));
      }
    });
  }, []);

  /* ---------------- Sync scroll / resize ---------------- */

  React.useEffect(() => {
    const el = scrollerRef.current;
    if (!el) return;

    const sync = () => {
      computeScrollState();
      if (openFor && anchorEl) updateMenuPosition(anchorEl);
    };

    el.addEventListener("scroll", sync, { passive: true });
    window.addEventListener("resize", sync);

    const doc = portalDocRef.current || document;
    const pwin = doc.defaultView;
    pwin?.addEventListener?.("scroll", sync, true);

    return () => {
      el.removeEventListener("scroll", sync);
      window.removeEventListener("resize", sync);
      pwin?.removeEventListener?.("scroll", sync, true);
    };
  }, [computeScrollState, openFor, anchorEl, updateMenuPosition]);

  /* ---------------- Close dropdown ---------------- */

  React.useEffect(() => {
    const doc = portalDocRef.current || document;

    const onDown = (e) => {
      if (!openFor) return;

      const menuBox = portalElRef.current?.querySelector?.("[data-menu-box='1']");
      const clickedInMenu = menuBox && menuBox.contains(e.target);
      const clickedAnchor = anchorEl && anchorEl.contains(e.target);

      if (!clickedInMenu && !clickedAnchor) {
        setOpenFor(null);
        setAnchorEl(null);
        setOpenMainKey(null);
      }
    };

    const onKey = (e) => {
      if (e.key === "Escape") {
        setOpenFor(null);
        setAnchorEl(null);
        setOpenMainKey(null);
      }
    };

    doc.addEventListener("mousedown", onDown, true);
    doc.addEventListener("keydown", onKey, true);

    return () => {
      doc.removeEventListener("mousedown", onDown, true);
      doc.removeEventListener("keydown", onKey, true);
    };
  }, [openFor, anchorEl]);

  /* ---------------- Theme tokens ---------------- */

  const t = React.useMemo(() => {
    const isDark = theme === "dark";
    return {
      isDark,
      text: isDark ? "rgba(255,255,255,0.92)" : "rgba(0,0,0,0.88)",
      pillText: isDark ? "rgba(255,255,255,0.92)" : "rgba(0,0,0,0.88)",

      selectedBg: isDark ? "rgba(255,255,255,0.16)" : "rgba(0,0,0,0.88)",
      selectedText: isDark ? "rgba(255,255,255,0.95)" : "rgba(255,255,255,0.98)",

      hoverBg: isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.06)",

      openBg: isDark ? "rgba(255,255,255,0.10)" : "rgba(0,0,0,0.10)",
      openText: isDark ? "rgba(255,255,255,0.95)" : "rgba(0,0,0,0.88)",

      fadeLeft: isDark
        ? "linear-gradient(to right, rgba(255,255,255,0.07), rgba(255,255,255,0))"
        : "linear-gradient(to right, rgba(0,0,0,0.08), rgba(0,0,0,0))",
      fadeRight: isDark
        ? "linear-gradient(to left, rgba(255,255,255,0.07), rgba(255,255,255,0))"
        : "linear-gradient(to left, rgba(0,0,0,0.08), rgba(0,0,0,0))",

      arrowBg: isDark ? "rgba(20,20,20,0.85)" : "rgba(255,255,255,0.95)",
      arrowBorder: isDark ? "rgba(255,255,255,0.14)" : "rgba(0,0,0,0.12)",

      menuBg: isDark ? "#1b1b1b" : "#fff",
      menuBorder: isDark ? "rgba(255,255,255,0.12)" : "rgba(0,0,0,0.15)",
      menuHover: isDark ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.06)",
      menuSelected: isDark ? "rgba(255,255,255,0.12)" : "rgba(0,0,0,0.08)",
      menuShadow: isDark
        ? "0 10px 28px rgba(0,0,0,0.40)"
        : "0 8px 22px rgba(0,0,0,0.10)",
    };
  }, [theme]);

  /* ---------------- Highlight logic (slug-only) ---------------- */

  const isSelectedMain = (item) => {
    const hasOptions = Array.isArray(item?.options) && item.options.length > 0;
    if (!selectedSlug) return false;

    if (hasOptions) {
      return item.options.some((o) => o?.slug && String(o.slug) === String(selectedSlug));
    }

    return item?.slug && String(item.slug) === String(selectedSlug);
  };

  const isOpenState = (item, idx) => {
    const k = mainKeyOf(item, idx);
    return openMainKey && String(openMainKey) === String(k);
  };

  /* ---------------- Handlers ---------------- */

  const scrollByAmount = (dir) => {
    const el = scrollerRef.current;
    if (!el) return;
    const amt = Math.floor(el.clientWidth * 0.7);
    el.scrollTo({
      left: el.scrollLeft + (dir === "left" ? -amt : amt),
      behavior: "smooth",
    });
  };

  const onMainClick = (item, idx, e) => {
    const hasOptions = Array.isArray(item?.options) && item.options.length > 0;

    if (!hasOptions) {
      const openInNewTab = !!(e?.metaKey || e?.ctrlKey);

      if (item?.slug) {
        setSelectedSlugState(item.slug);
        try {
          updateData({ ...data, selectedSlug: item.slug });
        } catch (_) {}
      }

      handleNavigation(item, openInNewTab);
      setOpenFor(null);
      setAnchorEl(null);
      setOpenMainKey(null);
      return;
    }

    setOpenFor(item);
    setAnchorEl(e.currentTarget);
    setOpenMainKey(mainKeyOf(item, idx));
    updateMenuPosition(e.currentTarget);
  };

  const onSubClick = (opt, e) => {
    const openInNewTab = !!(e?.metaKey || e?.ctrlKey);

    if (opt?.slug) {
      setSelectedSlugState(opt.slug);
      try {
        updateData({ ...data, selectedSlug: opt.slug });
      } catch (_) {}
    }

    handleNavigation(opt, openInNewTab);
    setOpenFor(null);
    setAnchorEl(null);
    setOpenMainKey(null);
  };

  /* ---------------- Dropdown render ---------------- */

  React.useEffect(() => {
    const root = portalRootRef.current;
    if (!root) return;

    if (!openFor || !Array.isArray(openFor.options)) {
      root.render(<></>);
      return;
    }

    root.render(
      <div
        data-menu-box="1"
        style={{
          position: "fixed",
          top: menuXY.top,
          left: menuXY.left,
          minWidth: menuXY.minWidth,
          maxWidth: 440,
          maxHeight: 320,
          overflow: "auto",
          background: t.menuBg,
          border: `1px solid ${t.menuBorder}`,
          borderRadius: 8,
          boxShadow: t.menuShadow,
          padding: 6,
          color: t.text,
          fontFamily: "system-ui, -apple-system, Segoe UI, Roboto, Arial",
        }}
      >
        {openFor.options.map((opt, i) => {
          const isSel =
            opt?.slug && selectedSlug && String(opt.slug) === String(selectedSlug);
          return (
            <div
              key={optKeyOf(opt, i)}
              onClick={(e) => onSubClick(opt, e)}
              style={{
                padding: "9px 10px",
                borderRadius: 8,
                cursor: "pointer",
                fontSize: 12.5,
                display: "flex",
                alignItems: "center",
                gap: 10,
                background: isSel ? t.menuSelected : "transparent",
              }}
              onMouseEnter={(e) => (e.currentTarget.style.background = t.menuHover)}
              onMouseLeave={(e) =>
                (e.currentTarget.style.background = isSel ? t.menuSelected : "transparent")
              }
              title={opt.label}
            >
              {opt?.icon ? (
                <span className="iconWrap" aria-hidden="true" dangerouslySetInnerHTML={{ __html: opt.icon }} />
              ) : null}

              <span style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", flex: 1 }}>
                {opt.label}
              </span>

              {isSel ? <span style={{ fontSize: 12, opacity: 0.85 }}>✓</span> : null}
            </div>
          );
        })}
      </div>,
    );
  }, [openFor, menuXY, selectedSlug, t, optKeyOf]);

  const ArrowIcon = ({ dir }) => (
    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" aria-hidden="true">
      <path
        d={dir === "left" ? "M15 6L9 12L15 18" : "M9 6L15 12L9 18"}
        stroke="currentColor"
        strokeWidth="2.5"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );

  /* ---------------- Render ---------------- */

  return (
    <div
      style={{
        position: "relative",
        width: "100%",
        height: 54,
        overflow: "hidden",
        display: "flex",
        alignItems: "center",
      }}
    >
      <style>{`
        .scroller {
          display: flex;
          align-items: center;
          gap: 12px;
          padding: 0 12px;
          overflow-x: auto;
          overflow-y: hidden;
          white-space: nowrap;
          scroll-behavior: smooth;
          scrollbar-width: none;
          -ms-overflow-style: none;
          width: 100%;
        }
        .scroller::-webkit-scrollbar { display: none; }

        .iconWrap {
          width: 16px;
          height: 16px;
          display: inline-flex;
          align-items: center;
          justify-content: center;
          flex: 0 0 auto;
        }
        .iconWrap svg { width: 16px; height: 16px; display: block; }

        .navBtn {
          border: none;
          background: transparent;
          color: ${t.pillText};
          padding: 8px 12px;
          border-radius: 8px;
          font-size: 13px;
          cursor: pointer;
          flex: 0 0 auto;
          line-height: 1;
          display: inline-flex;
          align-items: center;
          gap: 8px;
        }

        .navBtn:hover { background: ${t.hoverBg}; }

        .navBtn.selected:hover {
          background: ${t.selectedBg};
          color: ${t.selectedText};
        }

        .selected { background: ${t.selectedBg}; color: ${t.selectedText}; }
        .open { background: ${t.openBg}; color: ${t.openText}; }

        .edgeOverlay {
          position: absolute;
          top: 0;
          bottom: 0;
          width: 64px;
          z-index: 3;
          pointer-events: none;
          display: flex;
          align-items: center;
        }
        .edgeOverlay.left { left: 0; justify-content: flex-start; background: ${t.fadeLeft}; }
        .edgeOverlay.right { right: 0; justify-content: flex-end; background: ${t.fadeRight}; }

        .edgeBtn {
          pointer-events: auto;
          width: 34px;
          height: 34px;
          border-radius: 50%;
          display: grid;
          place-items: center;
          background: ${t.arrowBg};
          border: 1px solid ${t.arrowBorder};
          color: ${t.text};
          margin: 0 10px;
          cursor: pointer;
          padding: 0;
          line-height: 0;
        }
      `}</style>

      {canLeft ? (
        <div className="edgeOverlay left" aria-hidden="true">
          <button className="edgeBtn" onClick={() => scrollByAmount("left")} aria-label="Scroll left">
            <ArrowIcon dir="left" />
          </button>
        </div>
      ) : null}

      {canRight ? (
        <div className="edgeOverlay right" aria-hidden="true">
          <button className="edgeBtn" onClick={() => scrollByAmount("right")} aria-label="Scroll right">
            <ArrowIcon dir="right" />
          </button>
        </div>
      ) : null}

      <div ref={scrollerRef} className="scroller">
        {navItems.map((item, idx) => {
          const selected = isSelectedMain(item);
          const open = isOpenState(item, idx);
          const cls = `navBtn ${selected ? "selected" : open ? "open" : ""}`;

          return (
            <button
              key={mainKeyOf(item, idx)}
              className={cls}
              onClick={(e) => onMainClick(item, idx, e)}
            >
              {item?.icon ? (
                <span className="iconWrap" aria-hidden="true" dangerouslySetInnerHTML={{ __html: item.icon }} />
              ) : null}

              <span>{item.label}</span>
              {Array.isArray(item?.options) && item.options.length > 0 ? " ▾" : ""}
            </button>
          );
        })}
      </div>
    </div>
  );
};

export const ConnectedComponent = Tooljet.connectComponent(MyCustomComponent);

if (typeof document !== "undefined") {
  const root = createRoot(document.body);
  root.render(<ConnectedComponent />);
}
